mapper.select:
SELECT id, chat_room_id, sender_id, content, message_type, reference_type, reference_id, deleted_at, created_at
FROM chat_messages
WHERE id = #{id}

mapper.update:
UPDATE chat_messages
SET deleted_at = #{deletedAt}
WHERE id = #{id}

mapper.select:
SELECT id, chat_room_id, sender_id, content, message_type, reference_type, reference_id, deleted_at, created_at
FROM chat_messages
WHERE chat_room_id = #{chatRoomId}
ORDER BY id DESC
LIMIT #{limit}

SELECT id, chat_room_id, sender_id, content, message_type, reference_type, reference_id, deleted_at, created_at
FROM chat_messages
WHERE chat_room_id = #{chatRoomId}
  AND id < #{beforeId}
ORDER BY id DESC
LIMIT #{limit}

SELECT v.chat_room_id AS chat_room_id, COUNT(cm.id) AS unread_count FROM ( VALUES
(#{cursor.chatRoomId}::bigint, #{cursor.lastReadMessageId}::bigint)
) AS v(chat_room_id, last_read_message_id) LEFT JOIN chat_messages cm ON cm.chat_room_id = v.chat_room_id AND cm.id > COALESCE(v.last_read_message_id, 0) GROUP BY v.chat_room_id
